using namespace std;

int main() {
    // Example 1: Comparing Integers
    int num1 = 10; // num1 holds an integer value of 10
    int num2 = 20; // num2 holds an integer value of 20
    cout << "Example 1: " << (num1 < num2) << endl;  // Outputs: 1 (true)

    // Example 2: Comparing Floating-Point Numbers
    double price1 = 15.99; // price1 holds a double value of 15.99
    double price2 = 20.50; // price2 holds a double value of 20.50
    cout << "Example 2: " << (price1 < price2) << endl;  // Outputs: 1 (true)

    // Example 3: Comparing Mixed Types (Int and Float)
    int x = 5;    // x holds the integer value 5
    float y = 7.5f; // y holds the float value 7.5
    cout << "Example 3: " << (x < y) << endl;  // Outputs: 1 (true)

    return 0;
}
